import React, { useState } from 'react';

export default function AdminDashboard() {
  const [activeTab, setActiveTab] = useState('overview');

  const stats = [
    { label: 'Total Complaints', value: '145', icon: '📋', color: 'from-blue-400 to-blue-600' },
    { label: 'Pending', value: '23', icon: '⏳', color: 'from-yellow-400 to-yellow-600' },
    { label: 'Resolved', value: '112', icon: '✅', color: 'from-emerald-400 to-emerald-600' },
    { label: 'Avg Response', value: '2.4h', icon: '⚡', color: 'from-purple-400 to-purple-600' },
  ];

  const recentComplaints = [
    { id: 1, title: 'Wi-Fi not working in Hostel A', status: 'pending', priority: 'high' },
    { id: 2, title: 'Canteen food quality issue', status: 'in_progress', priority: 'medium' },
    { id: 3, title: 'Room maintenance required', status: 'resolved', priority: 'low' },
  ];

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="glass-card p-8 space-y-2">
        <h1 className="text-3xl font-bold text-slate-900">👨‍💼 Admin Dashboard</h1>
        <p className="text-slate-600">Manage complaints and monitor system performance</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => (
          <div key={idx} className={`glass-card p-6 space-y-3 bg-gradient-to-br ${stat.color}`}>
            <div className="text-4xl">{stat.icon}</div>
            <div>
              <p className="text-sm text-white/80">{stat.label}</p>
              <p className="text-3xl font-bold text-white">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div className="glass-card p-4 flex gap-2 flex-wrap">
        {[
          { id: 'overview', label: '📊 Overview' },
          { id: 'complaints', label: '📋 All Complaints' },
          { id: 'users', label: '👥 Users' },
          { id: 'analytics', label: '📈 Analytics' },
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`px-4 py-2 rounded-lg font-semibold transition-all ${
              activeTab === tab.id
                ? 'bg-blue-600 text-white'
                : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Content based on tab */}
      {activeTab === 'overview' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Recent Complaints */}
          <div className="lg:col-span-2 glass-card p-8 space-y-4">
            <h2 className="text-2xl font-bold text-slate-900">Recent Complaints</h2>
            <div className="space-y-3">
              {recentComplaints.map((complaint) => (
                <div key={complaint.id} className="p-4 bg-slate-50 rounded-lg flex items-center justify-between">
                  <div>
                    <p className="font-semibold text-slate-900">{complaint.title}</p>
                    <p className="text-sm text-slate-600">Priority: {complaint.priority}</p>
                  </div>
                  <span
                    className={`px-3 py-1 rounded-full text-sm font-semibold ${
                      complaint.status === 'resolved'
                        ? 'bg-emerald-100 text-emerald-700'
                        : complaint.status === 'in_progress'
                        ? 'bg-blue-100 text-blue-700'
                        : 'bg-yellow-100 text-yellow-700'
                    }`}
                  >
                    {complaint.status.replace('_', ' ')}
                  </span>
                </div>
              ))}
            </div>
          </div>

          {/* Quick Actions */}
          <div className="glass-card p-8 space-y-4">
            <h2 className="text-2xl font-bold text-slate-900">Quick Actions</h2>
            <div className="space-y-3">
              <button className="w-full px-4 py-3 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition-all">
                📝 Review Pending
              </button>
              <button className="w-full px-4 py-3 bg-emerald-600 text-white rounded-lg font-semibold hover:bg-emerald-700 transition-all">
                ✅ Approve Answers
              </button>
              <button className="w-full px-4 py-3 bg-purple-600 text-white rounded-lg font-semibold hover:bg-purple-700 transition-all">
                📊 View Reports
              </button>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'complaints' && (
        <div className="glass-card p-8">
          <h2 className="text-2xl font-bold text-slate-900 mb-4">All Complaints</h2>
          <p className="text-slate-600">Complaint management interface (coming soon)</p>
        </div>
      )}

      {activeTab === 'users' && (
        <div className="glass-card p-8">
          <h2 className="text-2xl font-bold text-slate-900 mb-4">User Management</h2>
          <p className="text-slate-600">User management interface (coming soon)</p>
        </div>
      )}

      {activeTab === 'analytics' && (
        <div className="glass-card p-8">
          <h2 className="text-2xl font-bold text-slate-900 mb-4">Analytics</h2>
          <p className="text-slate-600">Analytics dashboard (coming soon)</p>
        </div>
      )}
    </div>
  );
}
